import base64
import os
import qrcode
import hmac
import hashlib
import time
import struct
from flask import Flask, request, jsonify
from werkzeug.security import safe_str_cmp

app = Flask(__name__)

# In-memory storage for demonstration purposes
user_secrets = {}

def generate_totp_secret():
    return base64.b32encode(os.urandom(10)).decode('utf-8')

def generate_qr_code(username, secret):
    issuer = "YourAppName"
    uri = f"otpauth://totp/{issuer}:{username}?secret={secret}&issuer={issuer}"
    qr = qrcode.make(uri)
    qr.save(f"{username}_qrcode.png")

def get_totp_token(secret, interval=30):
    key = base64.b32decode(secret, True)
    msg = struct.pack(">Q", int(time.time()) // interval)
    hmac_digest = hmac.new(key, msg, hashlib.sha1).digest()
    ob = hmac_digest[19] & 15
    token = (struct.unpack(">I", hmac_digest[ob:ob + 4])[0] & 0x7fffffff) % 1000000
    return f"{token:06d}"

@app.route('/register', methods=['POST'])
def register():
    username = request.json.get('username')
    if not username:
        return jsonify({"error": "Invalid input"}), 400
    
    secret = generate_totp_secret()
    user_secrets[username] = secret
    generate_qr_code(username, secret)
    return jsonify({"message": "User registered successfully", "secret": secret})

@app.route('/validate', methods=['POST'])
def validate():
    username = request.json.get('username')
    token = request.json.get('token')
    
    if not username or not token:
        return jsonify({"error": "Invalid input"}), 400

    secret = user_secrets.get(username)
    if not secret:
        return jsonify({"error": "User not found"}), 404

    expected_token = get_totp_token(secret)
    if safe_str_cmp(expected_token, token):
        return jsonify({"message": "Validation successful"})
    else:
        return jsonify({"error": "Invalid token"}), 401

if __name__ == '__main__':
    app.run(ssl_context='adhoc')  # Use a proper SSL certificate in production